function clean(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function lowerFirst(value) {
  const text = clean(value).replace(/[.!?]+$/g, "");
  return text ? text.charAt(0).toLowerCase() + text.slice(1) : "";
}

function sentence(value) {
  const text = clean(value);
  if (!text) return "";
  const withCap = text.charAt(0).toUpperCase() + text.slice(1);
  return /[.!?]$/.test(withCap) ? withCap : `${withCap}.`;
}

function joinReadable(items) {
  const values = items.map((item) => lowerFirst(item)).filter(Boolean);
  if (values.length === 0) return "";
  if (values.length === 1) return values[0];
  if (values.length === 2) return `${values[0]} and ${values[1]}`;
  return `${values[0]}, ${values[1]}, and ${values[2]}`;
}

function slugify(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/['’]/g, "")
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function comparableTitle(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/['’]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function expandPractices(basePractices, targetCount) {
  const genericExtras = [
    "define the real constraint before reacting",
    "write down the assumption you are testing",
    "notice the first signal that should change your mind",
    "review the tradeoff before making the next move",
    "separate what is urgent from what is important",
    "check what future behavior the choice will encourage",
    "protect enough time to think before committing",
    "close the loop with a short review afterward",
  ];
  const next = [...basePractices.map((item) => lowerFirst(item))];
  for (const extra of genericExtras) {
    if (next.length >= targetCount) break;
    if (!next.includes(extra)) next.push(extra);
  }
  return next.slice(0, targetCount);
}

function buildBullets(chapter, practices, level) {
  const base = [
    sentence(`${chapter.focus} creates clearer judgment`),
    sentence(chapter.support),
    sentence(`This matters because ${chapter.importance}`),
    sentence(`A common mistake is ${chapter.mistake}`),
    sentence(`The pattern becomes easier to see when ${chapter.signal}`),
    sentence(`A practical starting move is to ${joinReadable(practices.slice(0, 3))}`),
  ];

  const mediumExtras = [
    sentence("The idea gets stronger when people connect the immediate choice to incentives, feedback, and downstream effects"),
    sentence("Small defaults and routines often decide whether the principle survives pressure"),
    sentence("For students and early career readers, the principle matters because early habits shape trust, options, and learning speed"),
    sentence("The real challenge is to stay deliberate without becoming rigid, reactive, or self defeating"),
  ];

  const hardExtras = [
    sentence("A deeper reading is that hidden assumptions and time horizons usually shape the result before the final decision is visible"),
    sentence("The long game improves when people treat evidence, reversibility, and tradeoffs as part of the same judgment process"),
    sentence("There is also an ethical dimension because clearer thinking should reduce avoidable harm instead of rewarding cleverness for its own sake"),
    sentence("The chapter is most useful when it strengthens calibration, restraint, and deliberate follow through at the same time"),
  ];

  if (level === "easy") return base;
  if (level === "medium") return [...base, ...mediumExtras];
  return [...base, ...mediumExtras, ...hardExtras];
}

function buildDetail(chapter, bulletIndex, practices) {
  const openers = [
    sentence(`This matters because ${chapter.importance}`),
    sentence(`The idea has value because ${chapter.importance}`),
    sentence(`The practical point is that ${chapter.importance}`),
    sentence(`The reason this helps is that ${chapter.importance}`),
  ];
  const mechanics = [
    sentence(`The supporting logic is that ${chapter.support}`),
    sentence(`Trouble usually starts when ${chapter.mistake}`),
    sentence(`It becomes easier to use when people stop ${chapter.mistake} and build more structure around the choice`),
    sentence(`The mechanism is simple: ${lowerFirst(chapter.support)}`),
  ];
  const signals = [
    sentence(`You can usually spot it when ${chapter.signal}`),
    sentence(`One sign is that ${chapter.signal}`),
    sentence(`In real situations, it becomes visible when ${chapter.signal}`),
    sentence(`The pattern is easier to notice when ${chapter.signal}`),
  ];
  const closing = [
    sentence(`A useful response is to ${practices[bulletIndex % practices.length]}`),
    sentence(`A better move is to ${practices[(bulletIndex + 1) % practices.length]}`),
    sentence(`One practical way to apply it is to ${practices[(bulletIndex + 2) % practices.length]}`),
    sentence(`Progress gets easier when people ${practices[(bulletIndex + 3) % practices.length]}`),
  ];

  return [
    openers[bulletIndex % openers.length],
    mechanics[bulletIndex % mechanics.length],
    signals[bulletIndex % signals.length],
    closing[bulletIndex % closing.length],
  ].join(" ");
}

function buildSummaryBlocks(chapter, bullets, practices) {
  const paragraphOne = sentence(
    `${chapter.title} explains the main pattern behind the chapter in a direct and practical way`
  );
  const paragraphTwo = [
    sentence(`In practice, these ideas matter because ${chapter.importance}`),
    sentence(`A useful starting move is to ${practices[0]}, then ${practices[1]}`),
    sentence("Repeated use builds better judgment over time because small decisions start aligning with longer term goals"),
  ].join(" ");

  return [
    {
      type: "paragraph",
      text: `${paragraphOne} One core idea is this: ${bullets[0]} Another key idea is this: ${bullets[1]}`,
    },
    {
      type: "paragraph",
      text: paragraphTwo,
    },
    ...bullets.map((bullet, index) => ({
      type: "bullet",
      text: bullet,
      detail: buildDetail(chapter, index, practices),
    })),
  ];
}

function buildVariant(chapter, level) {
  const count = level === "easy" ? 4 : level === "medium" ? 6 : 8;
  const practices = expandPractices(chapter.practices, count);
  const bullets = buildBullets(chapter, practices, level);
  return {
    summaryBullets: bullets,
    keyTakeaways: [
      `${bullets[0]} ${sentence(
        "This perspective helps people make clearer decisions and follow through with more discipline when stakes rise"
      )}`,
    ],
    practice: practices,
    summaryBlocks: buildSummaryBlocks(chapter, bullets, practices),
  };
}

function buildExamples(chapter, chapterNumber) {
  const practices = expandPractices(chapter.practices, 6);
  const baseReason = sentence(
    `This example matters because ${chapter.importance}. It turns the idea into a repeatable decision habit instead of a slogan`
  );
  const examplePlans = [
    ["personal", "Maya", `${chapter.title} in a personal decision`],
    ["personal", "Jordan", `${chapter.title} in a close relationship`],
    ["school", "Alex", `${chapter.title} in coursework`],
    ["school", "Priya", `${chapter.title} in a group project`],
    ["work", "Noah", `${chapter.title} at work`],
    ["work", "Elena", `${chapter.title} in team leadership`],
  ];

  return examplePlans.map(([context, name, title], index) => ({
    exampleId: `ch${String(chapterNumber).padStart(2, "0")}-ex${String(index + 1).padStart(2, "0")}`,
    title,
    contexts: [context],
    scenario: [
      sentence(`${name} is dealing with ${chapter.focus} in a ${context === "work" ? "work" : context === "school" ? "school" : "personal"} setting`),
      sentence(`${chapter.support}`),
      sentence(`Trouble starts when ${chapter.mistake}`),
      sentence(`The situation becomes clearer when ${chapter.signal}`),
    ].join(" "),
    whatToDo: [
      sentence(`Start by ${joinReadable(practices.slice(index % 4, (index % 4) + 2))}, then ${practices[(index + 2) % practices.length]}`),
    ],
    whyItMatters: baseReason,
  }));
}

function buildWrongChoices(chapter) {
  return [
    sentence("Fast certainty matters more than checking assumptions"),
    sentence("The first reasonable answer is usually enough once pressure rises"),
    sentence("More urgency usually fixes the problem without changing the process"),
    sentence("Visible effort matters more than clear feedback"),
    sentence("Short term relief is a reliable guide to good judgment"),
    sentence("The cleanest story is usually the most accurate one"),
    sentence(`The right move is ${chapter.mistake}`),
    sentence("It is better to react first and interpret later"),
    sentence("Structure matters only after formal authority is secured"),
    sentence("Good outcomes come mainly from intensity rather than consistency"),
  ];
}

function placeCorrectChoice(correct, wrongChoices, correctIndex) {
  const choices = [];
  let wrongIndex = 0;
  for (let i = 0; i < 4; i += 1) {
    if (i === correctIndex) {
      choices.push(correct);
    } else {
      choices.push(wrongChoices[wrongIndex]);
      wrongIndex += 1;
    }
  }
  return choices;
}

function buildQuiz(chapter, chapterNumber) {
  const mediumBullets = buildBullets(chapter, expandPractices(chapter.practices, 6), "medium");
  const hardBullets = buildBullets(chapter, expandPractices(chapter.practices, 8), "hard");
  const prompts = [
    "Which option best captures the core idea?",
    "Which option best explains a supporting idea?",
    "Which option best states why the idea matters?",
    "Which option identifies a mistake the chapter warns against?",
    "Which option points to a signal worth noticing?",
    "Which option shows a useful response?",
    "Which option reflects systems thinking around the choice?",
    "Which option shows why routines matter under pressure?",
    "Which option best explains why the idea matters early in a career?",
    "Which option describes the real challenge in applying the idea?",
  ];
  const retryPrompts = [
    "Which option best reflects a deeper reading of the principle?",
    "Which option best connects the idea to long term tradeoffs?",
    "Which option best captures the ethical edge of the idea?",
    "Which option best states the chapter's long game?",
    "Which option best applies the principle to a real decision?",
  ];
  const wrongChoices = buildWrongChoices(chapter);

  const questions = mediumBullets.slice(0, 10).map((correct, index) => {
    const correctIndex = (chapterNumber + index) % 4;
    const rotatedWrong = wrongChoices.slice(index % wrongChoices.length).concat(wrongChoices.slice(0, index % wrongChoices.length));
    return {
      questionId: `ch${String(chapterNumber).padStart(2, "0")}-h-q${String(index + 1).padStart(2, "0")}`,
      prompt: prompts[index],
      choices: placeCorrectChoice(correct, rotatedWrong.slice(0, 3), correctIndex),
      correctIndex,
    };
  });

  const retrySource = [hardBullets[10], hardBullets[11], hardBullets[12], hardBullets[13], mediumBullets[5]];
  const retryQuestions = retrySource.map((correct, index) => {
    const correctIndex = (chapterNumber + index + 2) % 4;
    const rotatedWrong = wrongChoices.slice((index + 4) % wrongChoices.length).concat(
      wrongChoices.slice(0, (index + 4) % wrongChoices.length)
    );
    return {
      questionId: `ch${String(chapterNumber).padStart(2, "0")}-h-q${String(index + 1).padStart(2, "0")}-retry-${String(index + 1).padStart(2, "0")}`,
      prompt: retryPrompts[index],
      choices: placeCorrectChoice(correct, rotatedWrong.slice(0, 3), correctIndex),
      correctIndex,
    };
  });

  return {
    passingScorePercent: 80,
    questions,
    retryQuestions,
  };
}

function buildChapter(chapter, chapterNumber) {
  return {
    chapterId: `ch${String(chapterNumber).padStart(2, "0")}-${chapter.slug}`,
    number: chapterNumber,
    title: chapter.title,
    readingTimeMinutes: 12 + ((chapterNumber + 1) % 3),
    contentVariants: {
      easy: buildVariant(chapter, "easy"),
      medium: buildVariant(chapter, "medium"),
      hard: buildVariant(chapter, "hard"),
    },
    examples: buildExamples(chapter, chapterNumber),
    quiz: buildQuiz(chapter, chapterNumber),
  };
}

function buildPackage(spec) {
  const bookId = slugify(spec.title);
  return {
    schemaVersion: SCHEMA_VERSION,
    packageId: randomUUID(),
    createdAt: CREATED_AT,
    contentOwner: CONTENT_OWNER,
    book: {
      bookId,
      title: spec.title,
      author: spec.author,
      categories: spec.categories,
      tags: spec.tags,
      edition: {
        name: "First Edition",
        publishedYear: spec.year,
      },
      variantFamily: VARIANT_FAMILY,
    },
    chapters: spec.chapters.map((chapter, index) => buildChapter(chapter, index + 1)),
  };
}

function existingTitles() {
  const files = fs.readdirSync(OUTPUT_DIR).filter((name) => name.endsWith(".json"));
  return new Set(
    files.map((fileName) => {
      const raw = JSON.parse(fs.readFileSync(path.join(OUTPUT_DIR, fileName), "utf8"));
      return comparableTitle(raw.book?.title || "");
    })
  );
}

function main() {
  const overwrite = process.argv.includes("--overwrite");
  const present = existingTitles();
  const created = [];
  const skipped = [];

  for (const spec of REQUESTED_BOOKS) {
    if (!overwrite && present.has(comparableTitle(spec.title))) {
      skipped.push(spec.title);
      continue;
    }
    const pkg = buildPackage(spec);
    const filePath = path.join(OUTPUT_DIR, `${slugify(spec.title)}.modern.json`);
    fs.writeFileSync(filePath, `${JSON.stringify(pkg, null, 2)}\n`, "utf8");
    created.push(spec.title);
  }

  console.log(
    JSON.stringify(
      {
        requested: REQUESTED_BOOKS.length,
        created: created.length,
        skippedExisting: skipped.length,
        overwrite,
        createdTitles: created,
        skippedTitles: skipped,
      },
      null,
      2
    )
  );
}

main();
